class Solution {
public:
    int smallestValue(int n) {
        int res = n;
        vector<bool> isPrime(n + 1, true);
        isPrime[0] = isPrime[1] = false;
        for (int i = 2; i * i <= n; i++) {
            if (isPrime[i]) {
                for (int j = i * i; j <= n; j += i) {
                    isPrime[j] = false;
                }
            }
        }
        while (true) {
            int sum = 0;
            for (int i = 2; i <= n; i++) {
                if (isPrime[i]) {
                    int cnt = 0;
                    while (n % i == 0) {
                        n /= i;
                        cnt++;
                    }
                    sum += cnt * i;
                }
            }
            if (sum < res) {
                res = sum;
            } else {
                break;
            }
        }
        return res;
    }
};
